// ─── SYSTEM PROMPT (fallback only, used if career not in our bank) ─────────
const SYSTEM_PROMPT = `You are a career assessment expert for India's job market. Generate exactly 20 multiple-choice questions for a career eligibility test.

DISTRIBUTION: 8 easy questions first, then 6 medium, then 6 hard.

USER LEVEL RULES:
- BEGINNER (Class 10/12/Fresher): Ask interest, aptitude, and personality-fit questions. NO technical jargon. Simple language.
- INTERMEDIATE (College student): Mix aptitude + basic domain concepts.
- ADVANCED (Experienced): Real industry knowledge, technical problem-solving, case studies.

SCORING: easy=5pts, medium=10pts, hard=15pts (max total = 8×5 + 6×10 + 6×15 = 190 pts)

Return ONLY valid JSON, no markdown:
{"questions":[{"id":1,"difficulty":"easy","question":"...","options":["A","B","C","D"],"correctIndex":0,"explanation":"...","points":5}]}

Make ALL questions SPECIFIC to the exact career title — not generic.`;

router.post("/career/eligibility-test", async (req, res) => {
  const { careerTitle, careerId, userLevel = "beginner", category = "Technology" } = req.body as {
    careerTitle?: string;
    careerId?: string;
    userLevel?: string;
    category?: string;
  };

  if (!careerTitle) {
    res.status(400).json({ error: "careerTitle is required" });
    return;
  }

  // 1. Try exact career ID match first (always works, no network needed)
  if (careerId && CAREER_QUESTIONS[careerId]) {
    res.json({ questions: CAREER_QUESTIONS[careerId] });
    return;
  }

  // 2. Try fuzzy title match
  const titleKey = Object.keys(CAREER_QUESTIONS).find(k =>
    careerTitle.toLowerCase().includes(k.replace(/-/g, " ")) ||
    k.replace(/-/g, " ").includes(careerTitle.toLowerCase().split(" ")[0])
  );
  if (titleKey) {
    res.json({ questions: CAREER_QUESTIONS[titleKey] });
    return;
  }

  // 3. Try OpenAI for careers not in our bank
  const apiKey = process.env["OPENAI_API_KEY"];
  if (apiKey) {
    try {
      const response = await fetch("https://api.openai.com/v1/chat/completions", {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${apiKey}` },
        body: JSON.stringify({
          model: "gpt-4o-mini",
          messages: [
            { role: "system", content: SYSTEM_PROMPT },
            { role: "user", content: `Generate 20 career eligibility test questions for: "${careerTitle}" (Category: ${category})\nUser Level: ${userLevel.toUpperCase()}\nAll questions must be SPECIFIC to "${careerTitle}".` },
          ],
          max_tokens: 4000,
          response_format: { type: "json_object" },
          temperature: 0.7,
        }),
      });

      if (response.ok) {
        const data = (await response.json()) as { choices: Array<{ message: { content: string } }> };
        const parsed = JSON.parse(data.choices[0].message.content);
        res.json(parsed);
        return;
      }
      req.log.warn({ status: response.status }, "OpenAI failed — no hardcoded questions for this career");
    } catch (err) {
      req.log.warn({ err }, "OpenAI error");
    }
  }

  // 4. Absolute fallback — generic questions for the category
  const categoryFallbacks: Record<string, string> = {
    "Technology": "full-stack-developer",
    "Healthcare": "doctor-mbbs",
    "Finance": "financial-analyst",
    "Business": "entrepreneur",
    "Law": "lawyer",
    "Engineering": "civil-engineer",
  };
  const fallbackId = categoryFallbacks[category] || "full-stack-developer";
  res.json({ questions: CAREER_QUESTIONS[fallbackId] });
});

export default router;
